// Server sets cookie (in Express)
res.cookie('token', 'abc123', {
  httpOnly: true,    // JavaScript can't read it (security!)
  secure: true,      // Only sent over HTTPS
  maxAge: 7 * 24 * 60 * 60 * 1000,  // 7 days
  sameSite: 'strict' // Prevent CSRF attacks
});

// JavaScript reads cookies (non-httpOnly only)
console.log(document.cookie);  // 'token=abc123; theme=dark'

// Save data
localStorage.setItem('username', 'Rajveer');
localStorage.setItem('settings', JSON.stringify({
  theme: 'dark',
  fontSize: 16
}));

// Read data
const name = localStorage.getItem('username');
const settings = JSON.parse(localStorage.getItem('settings'));

// Remove data
localStorage.removeItem('username');

// Clear everything
localStorage.clear();

// BAD: Storing JWT in localStorage
localStorage.setItem('token', jwtToken);  // XSS can steal it!

// GOOD: Storing JWT in httpOnly cookie
res.cookie('token', jwtToken, {
  httpOnly: true,
  secure: true,
  sameSite: 'strict'
});  // JavaScript can't access it

// GOOD: What to store in localStorage
localStorage.setItem('theme', 'dark');          // Non-sensitive
localStorage.setItem('language', 'en');        // Non-sensitive
